/**
 * Module: sound-notification
 *
 * Plays a sound on marker.add events.  Priority:
 *   1. Local WAV from /sounds/{severity}.wav  (generated by scripts/generate-sounds.py,
 *      bundled into Docker at build time via go:embed)
 *   2. Web Audio API synthesis fallback (works with zero files, any browser)
 *
 * Enabled via mapwatch.yaml:
 *   modules:
 *     sound: true
 *
 * Color → severity mapping (from DEMO.md palette):
 *   #FF4444 critical  #FF8844 high   #FFCC44 medium  #44FF44 low
 *   #4444FF info      #AA44FF test   #FFFFFF debug
 */
(function () {
  'use strict';

  // ── Severity resolution ───────────────────────────────────────────────────

  // Map dominant_color label (from RisingWave exporter) → severity name.
  const COLOR_TO_SEV = {
    '#ff4444': 'critical',
    '#ff8844': 'high',
    '#ffcc44': 'medium',
    '#44ff44': 'low',
    '#4444ff': 'info',
    '#aa44ff': 'test',
    '#ffffff': 'debug',
  };

  function severityFor(marker) {
    if (marker.severity) return marker.severity.toLowerCase();
    const col = (marker.labels && marker.labels.dominant_color || '').toLowerCase();
    return COLOR_TO_SEV[col] || 'info';
  }

  // ── WAV cache — pre-load once, reuse ─────────────────────────────────────

  const wavCache = {};  // severity → HTMLAudioElement | null (null = 404/load-error)

  function getWav(sev) {
    if (sev in wavCache) return wavCache[sev];
    const audio = new Audio('/sounds/' + sev + '.wav');
    audio.preload = 'auto';
    audio.onerror = function() { wavCache[sev] = null; };
    wavCache[sev] = audio;
    return audio;
  }

  // Pre-load all known severities on module load.
  ['critical','high','medium','low','info','test','debug'].forEach(getWav);

  // ── Web Audio API fallback ────────────────────────────────────────────────

  let audioCtx = null;

  function getCtx() {
    if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    return audioCtx;
  }

  // Synth params per severity  [freq_hz, duration_ms, gain, extra_beep]
  const SYNTH = {
    critical: [[880, 80, 0.55], [1108, 80, 0.55]],
    high:     [[880, 120, 0.45]],
    medium:   [[660, 100, 0.30], [784, 100, 0.30]],
    low:      [[528, 220, 0.25]],
    info:     [[440, 80, 0.20], [550, 80, 0.20]],
    test:     [[330, 60, 0.25], [440, 60, 0.25], [550, 60, 0.25]],
    debug:    [[220, 30, 0.12]],
  };

  function synthBeep(ctx, freq, durationMs, gain, startTime) {
    const osc = ctx.createOscillator();
    const g   = ctx.createGain();
    osc.connect(g); g.connect(ctx.destination);
    osc.frequency.value = freq;
    g.gain.setValueAtTime(0, startTime);
    g.gain.linearRampToValueAtTime(gain, startTime + 0.005);
    g.gain.linearRampToValueAtTime(0,    startTime + durationMs / 1000);
    osc.start(startTime);
    osc.stop(startTime + durationMs / 1000 + 0.01);
  }

  function playSynth(sev) {
    try {
      const ctx   = getCtx();
      const beeps = SYNTH[sev] || SYNTH.info;
      const schedule = function() {
        const gapSec = 0.04;
        let t = ctx.currentTime + 0.01;
        for (const [freq, dur, gain] of beeps) {
          synthBeep(ctx, freq, dur, gain, t);
          t += dur / 1000 + gapSec;
        }
      };
      if (ctx.state === 'suspended') {
        ctx.resume().then(schedule).catch(function() {});
      } else {
        schedule();
      }
    } catch (_) {}
  }

  // ── Play logic: WAV first, synth fallback ─────────────────────────────────

  function play(sev) {
    const audio = getWav(sev);
    if (audio && audio.readyState >= 2) {
      // WAV loaded — clone to allow rapid-fire overlapping plays.
      try {
        const clone = audio.cloneNode();
        clone.volume = 0.8;
        clone.play().catch(() => playSynth(sev));
        return;
      } catch (_) {}
    }
    // Fallback: synthesise.
    playSynth(sev);
  }

  // ── Sound-toggle button (injected into toolbar) ───────────────────────────

  let muted = false;

  function injectButton() {
    const toolbar = document.getElementById('toolbar');
    if (!toolbar) return;
    const sep = document.createElement('div');
    sep.className = 'tb-sep';
    const btn = document.createElement('button');
    btn.id        = 'btn-sound';
    btn.className = 'tb-btn active';
    btn.title     = 'Toggle alert sounds';
    btn.textContent = '🔔 Sound';
    btn.onclick = function() {
      muted = !muted;
      btn.classList.toggle('active', !muted);
      btn.textContent = muted ? '🔕 Sound' : '🔔 Sound';
    };
    toolbar.appendChild(sep);
    toolbar.appendChild(btn);
  }

  injectButton();

  // ── Register as MapWatch effect ───────────────────────────────────────────

  if (typeof MapWatch !== 'undefined' && MapWatch.registerEffect) {
    MapWatch.registerEffect('sound-notification', function (event) {
      if (event.type !== 'marker.add') return;
      if (muted) return;
      const m = event.marker;
      if (!m) return;
      play(severityFor(m));
    });
  }
})();
